#include <assert.h>
#include <stdio.h>
#include "sqlite3.h"

void test_open_memory_db(void) {
    sqlite3 *db;
    int rc = sqlite3_open(":memory:", &db);
    assert(rc == SQLITE_OK);
    sqlite3_close(db);
}

void test_create_table(void) {
    sqlite3 *db;
    sqlite3_open(":memory:", &db);
    int rc = sqlite3_exec(db, "CREATE TABLE test (id INTEGER PRIMARY KEY, name TEXT)", NULL, NULL, NULL);
    assert(rc == SQLITE_OK);
    sqlite3_close(db);
}

void test_insert_row(void) {
    sqlite3 *db;
    sqlite3_open(":memory:", &db);
    sqlite3_exec(db, "CREATE TABLE test (id INTEGER PRIMARY KEY, name TEXT)", NULL, NULL, NULL);
    int rc = sqlite3_exec(db, "INSERT INTO test (name) VALUES ('hello')", NULL, NULL, NULL);
    assert(rc == SQLITE_OK);
    sqlite3_close(db);
}

int main(void) {
    test_open_memory_db();
    test_create_table();
    test_insert_row();
    printf("All SQLite tests passed!\n");
    return 0;
}
